// Store remember me data in cookie with a expiration of 30 days
function rememberMe(username, hashedPassword) {
  var expires = new Date();
  expires.setTime(expires.getTime() + (30 * 24 * 60 * 60 * 1000));
  document.cookie = 'remember_me_username=' + username + ';expires=' + expires.toUTCString();
  document.cookie = 'remember_me_password=' + hashedPassword + ';expires=' + expires.toUTCString();
}

// Check if remember me data exists in cookie
function checkRememberMe() {
  const usernameCookie = getCookie('remember_me_username');
  const passwordCookie = getCookie('remember_me_password');

  if (usernameCookie && passwordCookie) {
    // Auto-login with the stored data
    document.getElementById('username').value = usernameCookie;
    document.getElementById('password').value = passwordCookie;
  }
}

// Get cookie by name
function getCookie(name) {
  var cookies = document.cookie.split(';');
  for (var i = 0; i < cookies.length; i++) {
    var cookie = cookies[i].trim();
    if (cookie.indexOf(name + '=') === 0) {
      return cookie.substring(name.length + 1);
    }
  }
  return null;
}